from collections import Counter
def char_ngram_counter(s, n=3):
    s = normalize(s)
    return Counter(s[i:i+n] for i in range(max(0, len(s)-n+1)))

def cosine_counter(ca, cb):
    # compute cosine similarity
    inter = 0
    for k in set(ca)|set(cb):
        inter += ca.get(k,0)*cb.get(k,0)
    norm_a = sum(v*v for v in ca.values())**0.5
    norm_b = sum(v*v for v in cb.values())**0.5
    if norm_a==0 or norm_b==0:
        return 0
    return inter/(norm_a*norm_b)
def cosine_char_ngram(a, b, n=3):
    return cosine_counter(char_ngram_counter(a,n), char_ngram_counter(b,n))

