def lcs_length(a, b):
    a = normalize(a)
    b = normalize(b)
    n, m = len(a), len(b)
    # we'll implement memory efficient
    prev = [0]*(m+1)
    for i in range(1, n+1):
        cur = [0]*(m+1)
        ai = a[i-1]
        for j in range(1, m+1):
            bj = b[j-1]
            if ai == bj:
                cur[j] = prev[j-1]+1
            else:
                cur[j] = max(prev[j], cur[j-1])
        prev = cur
    return prev[m]

def lcs_norm_min(a, b):
    L = lcs_length(a, b)
    la, lb = len(normalize(a)), len(normalize(b))
    return L / min(la, lb)

def lcs_norm_max(a, b):
    L = lcs_length(a, b)
    la, lb = len(normalize(a)), len(normalize(b))
    return L / max(la, lb)

